"use client";

/**
 * ShadcnContentSection — shadcn/Base UI card composition.
 *
 * This is the buyer-side component. It is NOT a MODE component — it has no
 * knowledge of PaletteMode or ComponentSlots. The MODE adapter (generated by
 * agent/ingest.js) wraps this and bridges the gap.
 *
 * Palette note:
 *   MODE passes palette as `className` (from the declaration's palette bridge).
 *   "dark" → adds `.dark` class which scopes shadcn's dark CSS vars to this
 *            section and all descendants (--card, --foreground, etc. flip).
 *   "bg-muted" → neutral section background; Card inside stays light.
 *   ""  (empty) → light mode default.
 *
 * Variant props (from declaration variants spread):
 *   layout="sidebar" → side-by-side body + callout panel
 *   showCallout=true → inline callout block within body column
 */

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { cn } from "@/lib/utils";

interface ShadcnContentSectionProps {
  headline: string;
  body: string;
  callout?: string;
  cta?: { label: string; href: string };
  /** Injected by palette bridge — "dark" scopes shadcn dark vars to this section */
  className?: string;
  /** Injected by variant map — "sidebar" puts callout in a side panel */
  layout?: "sidebar";
  /** Injected by variant map — true renders callout inline */
  showCallout?: boolean;
}

export function ShadcnContentSection({
  headline,
  body,
  callout,
  cta,
  className,
  layout,
  showCallout,
}: ShadcnContentSectionProps) {
  const isSidebar = layout === "sidebar";
  const showInlineCallout = (showCallout || (!isSidebar && !showCallout)) && !!callout;

  return (
    <section className={cn("w-full py-16 px-4", className)}>
      <div className={cn("mx-auto max-w-4xl", isSidebar && "flex gap-8 items-start")}>
        {/* Main card */}
        <Card className={cn("w-full", isSidebar && "flex-1")}>
          <CardHeader>
            <CardTitle className="text-2xl font-semibold">{headline}</CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col gap-6">
            <p className="text-muted-foreground leading-relaxed">{body}</p>

            {showInlineCallout && (
              <blockquote className="border-l-4 border-primary pl-4 text-foreground italic">
                {callout}
              </blockquote>
            )}

            {cta && (
              <a
                href={cta.href}
                className="inline-flex h-8 items-center justify-center rounded-lg bg-primary px-4 text-sm font-medium text-primary-foreground hover:bg-primary/80 transition-colors"
              >
                {cta.label}
              </a>
            )}
          </CardContent>
        </Card>

        {/* Sidebar callout panel (with-sidebar variant only) */}
        {isSidebar && callout && (
          <aside className="w-64 shrink-0">
            <Card>
              <CardContent className="pt-6">
                <p className="text-sm text-muted-foreground leading-relaxed">{callout}</p>
              </CardContent>
            </Card>
          </aside>
        )}
      </div>
    </section>
  );
}
